// ============================================================
// Higher-level idiomatic Zig wrappers
// ============================================================

pub const Error = error{
    Z3SortError,
    Z3IOB,
    Z3InvalidArg,
    Z3ParserError,
    Z3NoParser,
    Z3InvalidPattern,
    Z3MemoutFail,
    Z3FileAccessError,
    Z3InternalFatal,
    Z3InvalidUsage,
    Z3DecRefError,
    Z3Exception,
    Z3NullResult,
};

fn checkError(ctx: *z3.Z3_context) Error!void {
    const code = z3.Z3_get_error_code(ctx);
    return switch (code) {
        .OK => {},
        .SORT_ERROR => Error.Z3SortError,
        .IOB => Error.Z3IOB,
        .INVALID_ARG => Error.Z3InvalidArg,
        .PARSER_ERROR => Error.Z3ParserError,
        .NO_PARSER => Error.Z3NoParser,
        .INVALID_PATTERN => Error.Z3InvalidPattern,
        .MEMOUT_FAIL => Error.Z3MemoutFail,
        .FILE_ACCESS_ERROR => Error.Z3FileAccessError,
        .INTERNAL_FATAL => Error.Z3InternalFatal,
        .INVALID_USAGE => Error.Z3InvalidUsage,
        .DEC_REF_ERROR => Error.Z3DecRefError,
        .EXCEPTION => Error.Z3Exception,
    };
}

// ---- Config ----

pub const Config = struct {
    raw: *z3.Z3_config,

    pub fn init() Config {
        return .{ .raw = z3.Z3_mk_config().? };
    }

    pub fn deinit(self: Config) void {
        z3.Z3_del_config(self.raw);
    }

    pub fn set(self: Config, param: [:0]const u8, value: [:0]const u8) void {
        z3.Z3_set_param_value(self.raw, param, value);
    }
};

// ---- Context ----

pub const Context = struct {
    raw: *z3.Z3_context,

    pub fn init(cfg: Config) Context {
        return .{ .raw = z3.Z3_mk_context(cfg.raw).? };
    }

    /// Create a reference-counted context (use inc_ref/dec_ref on ASTs).
    pub fn initRc(cfg: Config) Context {
        return .{ .raw = z3.Z3_mk_context_rc(cfg.raw).? };
    }

    pub fn deinit(self: Context) void {
        z3.Z3_del_context(self.raw);
    }

    pub fn setErrorHandler(self: Context, handler: z3.Z3_error_handler) void {
        z3.Z3_set_error_handler(self.raw, handler);
    }

    // ---- Sorts ----

    pub fn boolSort(self: Context) Sort {
        return .{ .raw = z3.Z3_mk_bool_sort(self.raw).?, .ctx = self.raw };
    }
    pub fn intSort(self: Context) Sort {
        return .{ .raw = z3.Z3_mk_int_sort(self.raw).?, .ctx = self.raw };
    }
    pub fn realSort(self: Context) Sort {
        return .{ .raw = z3.Z3_mk_real_sort(self.raw).?, .ctx = self.raw };
    }
    pub fn bvSort(self: Context, size: u32) Sort {
        return .{ .raw = z3.Z3_mk_bv_sort(self.raw, @intCast(size)).?, .ctx = self.raw };
    }
    pub fn arraySort(self: Context, domain: Sort, range: Sort) Sort {
        return .{ .raw = z3.Z3_mk_array_sort(self.raw, domain.raw, range.raw).?, .ctx = self.raw };
    }

    // ---- Constants ----
    pub fn boolConst(self: Context, name: [:0]const u8) Ast {
        const sym = z3.Z3_mk_string_symbol(self.raw, name).?;
        const sort = z3.Z3_mk_bool_sort(self.raw).?;
        return .{ .raw = z3.Z3_mk_const(self.raw, sym, sort).?, .ctx = self.raw };
    }
    pub fn intConst(self: Context, name: [:0]const u8) Ast {
        const sym = z3.Z3_mk_string_symbol(self.raw, name).?;
        const sort = z3.Z3_mk_int_sort(self.raw).?;
        return .{ .raw = z3.Z3_mk_const(self.raw, sym, sort).?, .ctx = self.raw };
    }
    pub fn realConst(self: Context, name: [:0]const u8) Ast {
        const sym = z3.Z3_mk_string_symbol(self.raw, name).?;
        const sort = z3.Z3_mk_real_sort(self.raw).?;
        return .{ .raw = z3.Z3_mk_const(self.raw, sym, sort).?, .ctx = self.raw };
    }
    pub fn bvConst(self: Context, name: [:0]const u8, size: u32) Ast {
        const sym = z3.Z3_mk_string_symbol(self.raw, name).?;
        const sort = z3.Z3_mk_bv_sort(self.raw, @intCast(size)).?;
        return .{ .raw = z3.Z3_mk_const(self.raw, sym, sort).?, .ctx = self.raw };
    }

    // ---- Literals ----
    pub fn mkTrue(self: Context) Ast {
        return .{ .raw = z3.Z3_mk_true(self.raw).?, .ctx = self.raw };
    }
    pub fn mkFalse(self: Context) Ast {
        return .{ .raw = z3.Z3_mk_false(self.raw).?, .ctx = self.raw };
    }
    pub fn mkInt(self: Context, v: i64) Ast {
        const sort = z3.Z3_mk_int_sort(self.raw).?;
        return .{ .raw = z3.Z3_mk_int64(self.raw, v, sort).?, .ctx = self.raw };
    }
    pub fn mkUnsignedInt(self: Context, v: u64) Ast {
        const sort = z3.Z3_mk_int_sort(self.raw).?;
        return .{ .raw = z3.Z3_mk_unsigned_int64(self.raw, v, sort).?, .ctx = self.raw };
    }
    pub fn mkReal(self: Context, num: i32, den: i32) Ast {
        return .{ .raw = z3.Z3_mk_real(self.raw, @intCast(num), @intCast(den)).?, .ctx = self.raw };
    }
    pub fn mkNumeral(self: Context, s: [:0]const u8, sort: Sort) Ast {
        return .{ .raw = z3.Z3_mk_numeral(self.raw, s, sort.raw).?, .ctx = self.raw };
    }

    // ---- Solver ----
    pub fn mkSolver(self: Context) Solver {
        const s = z3.Z3_mk_solver(self.raw).?;
        z3.Z3_solver_inc_ref(self.raw, s);
        return .{ .raw = s, .ctx = self.raw };
    }
    pub fn mkSolverForLogic(self: Context, logic: [:0]const u8) Solver {
        const sym = z3.Z3_mk_string_symbol(self.raw, logic).?;
        const s = z3.Z3_mk_solver_for_logic(self.raw, sym).?;
        z3.Z3_solver_inc_ref(self.raw, s);
        return .{ .raw = s, .ctx = self.raw };
    }
    // TODO: Add mk_simple_solver and mk_solver_from_tactic
    // right now we keep this simple

    // ---- Optimize ----
    pub fn mkOptimize(self: Context) Optimize {
        const o = z3.Z3_mk_optimize(self.raw).?;
        z3.Z3_optimize_inc_ref(self.raw, o);
        return .{ .raw = o, .ctx = self.raw };
    }

    // ---- Version check ----
    pub fn getVersion() struct { major: u32, minor: u32, build: u32, revision: u32 } {
        var major: c_uint = 0;
        var minor: c_uint = 0;
        var build: c_uint = 0;
        var revision: c_uint = 0;
        z3.Z3_get_version(&major, &minor, &build, &revision);
        return .{
            .major = @intCast(major),
            .minor = @intCast(minor),
            .build = @intCast(build),
            .revision = @intCast(revision),
        };
    }
};

