// ---- AST wrapper ----

pub const Ast = struct {
    raw: *z3.Z3_ast,
    ctx: *z3.Z3_context, // TODO: should be a const pointer, or not held at all

    pub fn toString(self: Ast) ?[*:0]const u8 {
        return z3.Z3_ast_to_string(self.ctx, self.raw);
    }

    pub fn eql(self: Ast, other: Ast) bool {
        return z3.Z3_is_eq_ast(self.ctx, self.raw, other.raw);
    }

    pub fn getSort(self: Ast) Sort {
        return .{ .raw = z3.Z3_get_sort(self.ctx, self.raw).?, .ctx = self.ctx };
    }

    // Boolean ops
    pub fn not(self: Ast) Ast {
        return .{ .raw = z3.Z3_mk_not(self.ctx, self.raw).?, .ctx = self.ctx };
    }
    pub fn @"and"(self: Ast, other: Ast) Ast {
        var args = [2]?*z3.Z3_ast{ self.raw, other.raw };
        return .{ .raw = z3.Z3_mk_and(self.ctx, 2, &args).?, .ctx = self.ctx };
    }
    // TODO factor out the pattern into a function called doMany
    pub fn ands(self: Ast, others: []const Ast) Ast {
        const alloc = std.heap.page_allocator;
        const ptrs = alloc.alloc(?*z3.Z3_ast, others.len + 1) catch unreachable;
        defer alloc.free(ptrs);
        ptrs[0] = self.raw;
        for (others, 1..) |a, i| ptrs[i] = a.raw;
        return .{
            .raw = z3.Z3_mk_and(self.ctx, @intCast(ptrs.len), ptrs.ptr).?,
            .ctx = self.ctx,
        };
    }

    pub fn ors(self: Ast, others: []const Ast) Ast {
        const alloc = std.heap.page_allocator;
        const ptrs = alloc.alloc(?*z3.Z3_ast, others.len + 1) catch unreachable;
        defer alloc.free(ptrs);
        ptrs[0] = self.raw;
        for (others, 1..) |a, i| ptrs[i] = a.raw;
        return .{
            .raw = z3.Z3_mk_or(self.ctx, @intCast(ptrs.len), ptrs.ptr).?,
            .ctx = self.ctx,
        };
    }
    pub fn @"or"(self: Ast, other: Ast) Ast {
        var args = [2]?*z3.Z3_ast{ self.raw, other.raw };
        return .{ .raw = z3.Z3_mk_or(self.ctx, 2, &args).?, .ctx = self.ctx };
    }
    pub fn implies(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_implies(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }
    pub fn iff(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_iff(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }
    pub fn xor(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_xor(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }

    // Arithmetic ops
    pub fn add(self: Ast, other: Ast) Ast {
        var args = [2]?*z3.Z3_ast{ self.raw, other.raw };
        return .{ .raw = z3.Z3_mk_add(self.ctx, 2, &args).?, .ctx = self.ctx };
