    pub fn bvneg(self: Ast) Ast {
        return .{ .raw = z3.Z3_mk_bvneg(self.ctx, self.raw).?, .ctx = self.ctx };
    }
    pub fn bvshl(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_bvshl(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }
    pub fn bvlshr(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_bvlshr(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }
    pub fn bvashr(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_bvashr(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }
    pub fn bvult(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_bvult(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }
    pub fn bvslt(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_bvslt(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }
    pub fn extract(self: Ast, high: u32, low: u32) Ast {
        return .{ .raw = z3.Z3_mk_extract(self.ctx, @intCast(high), @intCast(low), self.raw).?, .ctx = self.ctx };
    }
    pub fn concat(self: Ast, other: Ast) Ast {
        return .{ .raw = z3.Z3_mk_concat(self.ctx, self.raw, other.raw).?, .ctx = self.ctx };
    }

    // Array ops
    pub fn select(self: Ast, idx: Ast) Ast {
        return .{ .raw = z3.Z3_mk_select(self.ctx, self.raw, idx.raw).?, .ctx = self.ctx };
    }
    pub fn store(self: Ast, idx: Ast, val: Ast) Ast {
        return .{ .raw = z3.Z3_mk_store(self.ctx, self.raw, idx.raw, val.raw).?, .ctx = self.ctx };
    }

    // Simplify
    pub fn simplify(self: Ast) Ast {
        return .{ .raw = z3.Z3_simplify(self.ctx, self.raw).?, .ctx = self.ctx };
    }
};

// ---- Model wrapper ----

pub const Model = struct {
    raw: *z3.Z3_model,
    ctx: *z3.Z3_context,

    pub fn deinit(self: Model) void {
        z3.Z3_model_dec_ref(self.ctx, self.raw);
    }

    pub fn toString(self: Model) ?[*:0]const u8 {
        return z3.Z3_model_to_string(self.ctx, self.raw);
    }

    /// Evaluate an expression in the model. Returns null if evaluation fails.
    pub fn eval(self: Model, expr: Ast, completion: bool) ?Ast {
        var result: ?*z3.Z3_ast = null;
        if (z3.Z3_model_eval(self.ctx, self.raw, expr.raw, completion, &result)) {
            return .{ .raw = result.?, .ctx = self.ctx };
        }
        return null;
    }

    pub fn numConsts(self: Model) u32 {
        return @intCast(z3.Z3_model_get_num_consts(self.ctx, self.raw));
    }
    pub fn numFuncs(self: Model) u32 {
        return @intCast(z3.Z3_model_get_num_funcs(self.ctx, self.raw));
    }
};

// ---- Solver wrapper ----

pub const CheckResult = enum {
    sat,
    unsat,
    unknown,
};

pub const Solver = struct {
    raw: *z3.Z3_solver,
    ctx: *z3.Z3_context,

    pub fn deinit(self: Solver) void {
        z3.Z3_solver_dec_ref(self.ctx, self.raw);
    }

    pub fn assert(self: Solver, expr: Ast) void {
        z3.Z3_solver_assert(self.ctx, self.raw, expr.raw);
    }

    pub fn push(self: Solver) void {
        z3.Z3_solver_push(self.ctx, self.raw);
    }

    pub fn pop(self: Solver, n: u32) void {
        z3.Z3_solver_pop(self.ctx, self.raw, @intCast(n));
    }

    pub fn reset(self: Solver) void {
        z3.Z3_solver_reset(self.ctx, self.raw);
    }

    pub fn check(self: Solver) CheckResult {
        return switch (z3.Z3_solver_check(self.ctx, self.raw)) {
            .L_TRUE => .sat,
            .L_FALSE => .unsat,
            .L_UNDEF => .unknown,
        };
    }

    pub fn checkAssumptions(self: Solver, assumptions: []const Ast) CheckResult {
        const ptrs = std.heap.page_allocator.alloc(?*z3.Z3_ast, assumptions.len) catch return .unknown;
        defer std.heap.page_allocator.free(ptrs);
        for (assumptions, 0..) |a, i| ptrs[i] = a.raw;
        return switch (z3.Z3_solver_check_assumptions(self.ctx, self.raw, @intCast(ptrs.len), ptrs.ptr)) {
            .L_TRUE => .sat,
            .L_FALSE => .unsat,
            .L_UNDEF => .unknown,
        };
    }

    pub fn getModel(self: Solver) ?Model {
        const m = z3.Z3_solver_get_model(self.ctx, self.raw) orelse return null;
        z3.Z3_model_inc_ref(self.ctx, m);
        return .{ .raw = m, .ctx = self.ctx };
    }

    pub fn getUnsatCore(self: Solver) AstVector {
        const v = z3.Z3_solver_get_unsat_core(self.ctx, self.raw).?;
        z3.Z3_ast_vector_inc_ref(self.ctx, v);
        return .{ .raw = v, .ctx = self.ctx };
    }

    pub fn getReasonUnknown(self: Solver) ?[*:0]const u8 {
        return z3.Z3_solver_get_reason_unknown(self.ctx, self.raw);
    }

    pub fn toString(self: Solver) ?[*:0]const u8 {
        return z3.Z3_solver_to_string(self.ctx, self.raw);
    }

    pub fn numScopes(self: Solver) u32 {
        return @intCast(z3.Z3_solver_get_num_scopes(self.ctx, self.raw));
    }
};

// ---- Optimize wrapper ----

pub const Optimize = struct {
    raw: *z3.Z3_optimize,
    ctx: *z3.Z3_context,

    pub fn deinit(self: Optimize) void {
        z3.Z3_optimize_dec_ref(self.ctx, self.raw);
    }

    pub fn assert(self: Optimize, expr: Ast) void {
        z3.Z3_optimize_assert(self.ctx, self.raw, expr.raw);
    }

    pub fn maximize(self: Optimize, expr: Ast) u32 {
        return @intCast(z3.Z3_optimize_maximize(self.ctx, self.raw, expr.raw));
    }

    pub fn minimize(self: Optimize, expr: Ast) u32 {
        return @intCast(z3.Z3_optimize_minimize(self.ctx, self.raw, expr.raw));
    }

    pub fn check(self: Optimize) CheckResult {
        return switch (z3.Z3_optimize_check(self.ctx, self.raw, 0, undefined)) {
            .L_TRUE => .sat,
            .L_FALSE => .unsat,
            .L_UNDEF => .unknown,
        };
    }

    pub fn getModel(self: Optimize) ?Model {
        const m = z3.Z3_optimize_get_model(self.ctx, self.raw) orelse return null;
        z3.Z3_model_inc_ref(self.ctx, m);
        return .{ .raw = m, .ctx = self.ctx };
    }

    pub fn getLower(self: Optimize, idx: u32) Ast {
        return .{ .raw = z3.Z3_optimize_get_lower(self.ctx, self.raw, @intCast(idx)).?, .ctx = self.ctx };
    }

    pub fn getUpper(self: Optimize, idx: u32) Ast {
        return .{ .raw = z3.Z3_optimize_get_upper(self.ctx, self.raw, @intCast(idx)).?, .ctx = self.ctx };
    }

    pub fn toString(self: Optimize) ?[*:0]const u8 {
        return z3.Z3_optimize_to_string(self.ctx, self.raw);
    }
};

